QUnit.module("Plugin — Initialization",function(hooks){hooks.beforeEach(function(){$("#qunit-fixture").html('<div id="cal"></div>')});hooks.afterEach(function(){try{$("#cal").bsCalendar("destroy")}catch(e){}$(".bs-calendar-info-modal").remove()});QUnit.test("initializes without throwing",function(assert){assert.expect(1);assert.ok(function(){$("#cal").bsCalendar();return true}())});QUnit.test("stores instance data on the element",function(assert){$("#cal").bsCalendar();assert.ok($("#cal").data("bsCalendar")!==undefined)});QUnit.test("data.settings reflects passed options",function(assert){$("#cal").bsCalendar({locale:"de-DE",startView:"week"});const data=$("#cal").data("bsCalendar");assert.strictEqual(data.settings.locale,"de-DE");assert.strictEqual(data.settings.startView,"week")});QUnit.test('normalizes underscore locale "de_DE" to "de-DE"',function(assert){$("#cal").bsCalendar({locale:"de_DE"});const data=$("#cal").data("bsCalendar");assert.strictEqual(data.settings.locale,"de-DE")});QUnit.test("uses DEFAULTS when no options are passed",function(assert){$("#cal").bsCalendar();const data=$("#cal").data("bsCalendar");assert.strictEqual(data.settings.mainColor,"primary");assert.strictEqual(data.settings.startView,"month")});QUnit.test("renders wrapper markup inside the element",function(assert){$("#cal").bsCalendar();assert.ok($("#cal").children().length>0,"element has rendered children")});QUnit.test("destroy removes rendered markup",function(assert){$("#cal").bsCalendar();assert.ok($("#cal").children().length>0,"has markup before destroy");$("#cal").bsCalendar("destroy");assert.strictEqual($("#cal").children().length,0,"no markup after destroy")});QUnit.test("destroy removes instance data",function(assert){$("#cal").bsCalendar();$("#cal").bsCalendar("destroy");assert.strictEqual($("#cal").data("bsCalendar"),undefined)});QUnit.test("multiple instances on separate elements are independent",function(assert){$("#qunit-fixture").append('<div id="cal2"></div>');$("#cal").bsCalendar({locale:"de-DE"});$("#cal2").bsCalendar({locale:"fr-FR"});const d1=$("#cal").data("bsCalendar");const d2=$("#cal2").data("bsCalendar");assert.strictEqual(d1.settings.locale,"de-DE");assert.strictEqual(d2.settings.locale,"fr-FR");assert.notEqual(d1,d2,"separate data objects");try{$("#cal2").bsCalendar("destroy")}catch(e){}})});